#!run
// @acepad/tsify
import {sibling} from "@acepad/here";
export function main(){
  const c=this.resolve(".");
  this.mkdir("src/");
  this.mkdir("js/");
  this.cp(sibling(import.meta.url,"tsconfig.json"), ".");
  for (let f of this.glob("*.js")){
    this.cp(f, `src/${c.rel(f).truncExt()}.ts`);
    this.mv(f, "js/");
  }
  const p=this.obj("package.json");
  const main=c.rel(p.main);
  p.main="./"+c.rel("js/").rel(main.name()).relPath(c);
  this.obj(p);
}